    match e {
        // Or-pattern: Io and Parse both come from external sources
        ConfigError::Io(_) | ConfigError::Parse(_) => "system",
        // Or-pattern with struct variant and tuple variant:
        ConfigError::Missing(_) | ConfigError::Validation { .. } => "config",
    }
}

fn is_retryable(e: &ConfigError) -> bool {
    matches!(e, ConfigError::Io(_))
}

