// Filter with or-patterns:
fn extract_keywords<'a>(tokens: &[&'a str]) -> Vec<&'a str> {
    tokens.iter()
        .filter(|&&t| matches!(t, "if" | "else" | "while" | "for" | "fn" | "let"))
        .copied()
        .collect()
}

// Match inside for body:
fn annotate(tokens: &[&str]) {
    for &t in tokens {
        let kind = match t {
            "true" | "false"                 => "bool",
            "if" | "else" | "while" | "for"  => "control",
            "fn" | "let" | "mut" | "const"   => "decl",
            t if t.starts_with('"')          => "string",
            t if t.chars().all(|c| c.is_ascii_digit()) => "number",
            _                                => "ident",
        };
        println!("{:?}: {}", t, kind);
    }
}

fn main() {
    let tokens = ["true", "if", "x", "42", "fn", "let", "false"];
    process_tokens(&tokens);
    println!("keywords: {:?}", extract_keywords(&tokens));
    annotate(&["true", "if", "myvar", "42", "fn"]);
}

