use std::num::ParseIntError;
use std::fmt;

#[derive(Debug)]
enum MyError {
    Parse(ParseIntError),
    TooLarge(i64),
    Negative(i64),
    Empty,
}

impl fmt::Display for MyError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            MyError::Parse(e)    => write!(f, "parse: {}", e),
            MyError::TooLarge(n) => write!(f, "too large: {}", n),
            MyError::Negative(n) => write!(f, "negative: {}", n),
            MyError::Empty       => write!(f, "empty input"),
        }
    }
}

fn parse_bounded(s: &str, max: i64) -> Result<i64, MyError> {
    let s = s.trim();
    if s.is_empty() { return Err(MyError::Empty); }
    let n: i64 = s.parse().map_err(MyError::Parse)?;
    if n < 0   { return Err(MyError::Negative(n)); }
    if n > max  { return Err(MyError::TooLarge(n)); }
    Ok(n)
}

fn should_retry(e: &MyError) -> bool {
    // Parsing and empty errors might be user mistakes worth retrying:
    matches!(e, MyError::Parse(_) | MyError::Empty)
}

fn error_code(e: &MyError) -> u32 {
    match e {
        MyError::Parse(_) | MyError::Empty      => 400, // bad input
        MyError::Negative(_) | MyError::TooLarge(_) => 422, // validation
    }
}

fn main() {
    for (s, max) in [("42", 100i64), ("bad", 100), ("-1", 100), ("999", 100), ("", 100)] {
        match parse_bounded(s, max) {
            Ok(n) => println!("{:?} -> {}", s, n),
            Err(e) => println!("{:?} -> {} (code={} retry={})",
                s, e, error_code(&e), should_retry(&e)),
        }
    }
}

