#[derive(Debug, Clone, Copy, PartialEq)]
enum TrafficLight {
    Red, Yellow, Green, FlashingRed, FlashingYellow,
}

impl TrafficLight {
    fn next(self) -> TrafficLight {
        match self {
            TrafficLight::Green  => TrafficLight::Yellow,
            TrafficLight::Yellow => TrafficLight::Red,
            TrafficLight::Red    => TrafficLight::Green,
            // Or-pattern: both flashing states loop back to themselves:
            TrafficLight::FlashingRed | TrafficLight::FlashingYellow => self,
        }
    }

    fn is_warning(self) -> bool {
        matches!(self,
            TrafficLight::Yellow |
            TrafficLight::FlashingRed |
            TrafficLight::FlashingYellow
        )
    }

    fn is_steady(self) -> bool {
        !matches!(self, TrafficLight::FlashingRed | TrafficLight::FlashingYellow)
    }
}

fn main() {
    let mut light = TrafficLight::Green;
    for _ in 0..5 {
        println!("{:?}: warning={} steady={}", light, light.is_warning(), light.is_steady());
        light = light.next();
    }
}

