fn drain_until_sentinel(v: &mut Vec<i32>) -> Vec<i32> {
    let mut result = Vec::new();
    // while let with negated or-pattern using an if guard:
    while matches!(v.last(), Some(n) if !matches!(n, 0 | -1)) {
        result.push(v.pop().unwrap());
    }
    result
}

// Alternative: explicit sentinel check with or-pattern:
fn pop_positives(v: &mut Vec<i32>) -> Vec<i32> {
    let mut out = Vec::new();
    loop {
        match v.last().copied() {
            None | Some(i32::MIN..=-1) | Some(0) => break,
            Some(n) => { v.pop(); out.push(n); }
        }
    }
    out
}

// Process a stream of events until Stop or Error:
#[derive(Debug)]
enum Event { Data(i32), Stop, Error(String), Pause }

fn collect_until_done(events: Vec<Event>) -> (Vec<i32>, Option<String>) {
    let mut data = Vec::new();
    let mut error = None;
    for ev in events {
        match ev {
            Event::Stop | Event::Error(_) if matches!(ev, Event::Stop) => break,
            Event::Error(e) => { error = Some(e); break; }
            Event::Pause => continue,
            Event::Data(n) => data.push(n),
            Event::Stop => break,
        }
    }
    (data, error)
}

fn main() {
    let mut v = vec![5, 3, 0, 2, 7, 1];
